import React from "react";

const Values = {
    title: 'Eskalering av våldet och vägen ut',
    video: {
        title: 'Eskalering och vägen ut',
        link: 'https://www.youtube-nocookie.com/embed/s3BLyaHEvhI',
    },
    text: [
        'Gulderens situation blev sämre, innan den blev bättre. Våldet blev värre och hon visste inte hur hon skulle ta sig ur situationen. Hon bestämde sig för att lämna relationen och lyckades hitta en väg ut.',
    ],
    subtitle: 'Våldets normaliseringsprocess',
    paragraphs: [
        'Normaliseringsprocessen är ett sätt att förklara våldsprocessen som händer i nära relationer. Med tiden börjar den som utsätts för våld förvänta sig våldet och se det som en del av sin vardag. För att kunna hantera en vardag fylld med hot och våld skapar den våldsutsatta strategier för att förklara våldet för sig själv och andra. Förövaren försvarar våldshandlingarna genom att skuldbelägga den utsatta. Den utsatta får då anpassa sina strategier för att kunna hantera sin utsatthet. Normaliseringsprocessen förklarar hur våld kan bli en normal del av en relation och varför kvinnor stannar i relationen med en våldsam man.',
        'Våldsutövaren skapar en normalsiering av våld genom att ha:',
    ],
    list: [
        'Kontrollerad gränsmarkering: använder kontrollerande våldshandlingar som olika former av våld.',
        'Isolering som kan vara fysisk och mental; hindra den utsatta att träffa folk eller hotar personen.',
        'Växling mellan våld och värme: han växlar mellan att vara kärleksfull eller att vara våldsam.',
    ],
    ref: <em>KÄLLA (Sinisalo, E. Hällen, L. Våld i nära relation. 2018 s. 30).</em>,
    reflect: [
        'Vad kan man göra för att motverka en normaliseringsprocess?',
    ],
}
export default Values;
